/// Standalone admin moderation log page.
pub fn mod_log_page(
    entries: &[crate::models::ModLogEntry],
    pagination: &crate::models::Pagination,
    csrf_token: &str,
    boards: &[Board],
) -> String {
    let mut rows = String::new();
    if entries.is_empty() {
        rows.push_str(r#"<tr><td colspan="6" style="color:var(--text-dim);text-align:center">no entries yet</td></tr>"#);
    }
    for e in entries {
        let target = if let Some(id) = e.target_id {
            format!("{} #{}", e.target_type, id)
        } else {
            e.target_type.clone()
        };
        let board_link = if !e.board_short.is_empty() {
            format!(
                r#"<a href="/{s}/">{s}</a>"#,
                s = escape_html(&e.board_short)
            )
        } else {
            String::new()
        };
        rows.push_str(&format!(
            r#"<tr>
<td style="white-space:nowrap;font-size:0.78rem">{time}</td>
<td><strong>{admin}</strong></td>
<td><code>{action}</code></td>
<td style="font-size:0.82rem">{target}</td>
<td>{board}</td>
<td style="max-width:260px;overflow:hidden;text-overflow:ellipsis;white-space:nowrap;font-size:0.8rem"
    title="{detail}">{detail}</td>
</tr>"#,
            time   = escape_html(&fmt_ts(e.created_at)),
            admin  = escape_html(&e.admin_name),
            action = escape_html(&e.action),
            target = escape_html(&target),
            board  = board_link,
            detail = escape_html(&e.detail),
        ));
    }

    let pagination_html = render_pagination(pagination, "/admin/mod-log");

    let body = format!(
        r#"<div class="page-box">
<div class="board-header">
  <a href="/admin/panel">[ back to panel ]</a>
  <h2 style="margin:0.5rem 0 0.25rem">// moderation log</h2>
  <p style="color:var(--text-dim);font-size:0.82rem">{total} total entries</p>
</div>
<table class="admin-table" style="width:100%;font-size:0.85rem">
<thead><tr>
  <th>time</th><th>admin</th><th>action</th><th>target</th><th>board</th><th>detail</th>
</tr></thead>
<tbody>{rows}</tbody>
</table>
{pagination}
</div>"#,
        total = pagination.total,
        rows = rows,
        pagination = pagination_html,
    );

    base_layout(
        "mod log — admin",
        None,
        &body,
        csrf_token,
        boards,
        false,
        false,
    )
}

use chrono::{TimeZone, Utc};

// ─── Timestamp helpers ────────────────────────────────────────────────────────

/// Scan raw post body text for a video embed URL and return its thumbnail URL.
/// Used by catalog and board-index summaries when the OP has no uploaded file.
/// Currently returns YouTube thumbnails only (Streamable has no public thumb API).
fn embed_thumb_from_body(body: &str) -> Option<String> {
    for token in body.split_whitespace() {
        // Strip trailing punctuation the same way render_inline does
        let clean = token.trim_end_matches(['.', ',', ')', ';', '\'']);
        if let Some((embed_type, id)) = crate::utils::sanitize::extract_video_embed(clean) {
            if embed_type == "youtube" {
                return Some(format!("https://img.youtube.com/vi/{}/mqdefault.jpg", id));
            }
        }
    }
    None
}

fn fmt_ts(ts: i64) -> String {
    match Utc.timestamp_opt(ts, 0) {
        chrono::LocalResult::Single(dt) => dt.format("%Y-%m-%d %H:%M:%S UTC").to_string(),
        _ => "unknown".to_string(),
    }
}

fn fmt_ts_short(ts: i64) -> String {
    match Utc.timestamp_opt(ts, 0) {
        chrono::LocalResult::Single(dt) => dt.format("%m/%d/%y(%a)%H:%M:%S").to_string(),
        _ => "?".to_string(),
    }
}

// ─── Base layout ─────────────────────────────────────────────────────────────

fn base_layout(
    title: &str,
    board_short: Option<&str>,
    body: &str,
    csrf_token: &str,
    boards: &[Board],
    collapse_greentext: bool,
    _allow_archive: bool,
) -> String {
    let inner_links: String = boards
        .iter()
        .map(|b| {
            format!(
                r#"<a href="/{s}/catalog">{s}</a>"#,
                s = escape_html(&b.short_name)
            )
        })
        .collect::<Vec<_>>()
        .join(" / ");
    let board_links = if inner_links.is_empty() {
        String::new()
    } else {
        format!("[ {} ]", inner_links)
    };

    let search_bar = if let Some(b) = board_short {
        format!(
            r#"<form class="search-form" method="GET" action="/{b}/search">
<input type="text" name="q" placeholder="search /{b}/…" maxlength="64">
<button type="submit">go</button>
</form>"#,
            b = escape_html(b)
        )
    } else {
        String::new()
    };

    format!(
        r#"<!DOCTYPE html>
<html lang="en">
<head>
<meta charset="utf-8">
<meta name="viewport" content="width=device-width, initial-scale=1">
<meta name="referrer" content="no-referrer">
<title>{title}</title>
<link rel="stylesheet" href="/static/style.css">
<script src="/static/theme-init.js"></script>
</head>
<body{collapse_attr}>
<header class="site-header">
  <span class="site-name">{forum_name}</span>
  <a class="home-btn" href="/">&#8962; Home</a>
  <nav class="board-list">
    {board_links}
  </nav>
  <div class="header-search">{search_bar}</div>
  <a class="admin-header-link" href="/admin">[Admin]</a>
</header>
<main>
{body}
</main>
<footer class="site-footer">
  <p>{forum_name} &mdash; <a href="/">home</a></p>
</footer>

<!-- Theme Picker — FIX[NEW-H1]: onclick= replaced with data-action= attributes -->
<button id="theme-picker-btn" data-action="toggle-theme-picker" title="Select Theme">&#127912; Theme</button>
<div id="theme-picker-panel">
  <div class="tp-title">// SELECT THEME</div>
  <button class="tp-option" data-action="set-theme" data-theme="terminal">
    <span class="tp-swatch" style="background:#00ff41;"></span>Terminal
  </button>
  <button class="tp-option" data-action="set-theme" data-theme="aero">
    <span class="tp-swatch" style="background:#6aaed6;"></span>Frutiger Aero
  </button>
  <button class="tp-option" data-action="set-theme" data-theme="dorfic">
    <span class="tp-swatch" style="background:#ffcc66;"></span>DORFic
  </button>
  <button class="tp-option" data-action="set-theme" data-theme="fluorogrid">
    <span class="tp-swatch" style="background:#8833aa;"></span>FluoroGrid
  </button>
  <button class="tp-option" data-action="set-theme" data-theme="neoncubicle">
    <span class="tp-swatch" style="background:#b03888;"></span>NeonCubicle
  </button>
</div>

<input type="hidden" id="csrf_global" value="{csrf_token}">
<script src="/static/main.js" defer></script>
</body>
</html>"#,
        title = escape_html(title),
        board_links = board_links,
        search_bar = search_bar,
        forum_name = escape_html(&live_site_name()),
        body = body,
        csrf_token = escape_html(csrf_token),
        collapse_attr = if collapse_greentext {
            " data-collapse-greentext=\"1\""
        } else {
            ""
        },
    )
}

// ─── Index (board list) ───────────────────────────────────────────────────────

pub fn index_page(
    board_stats: &[crate::models::BoardStats],
    site_stats: &crate::models::SiteStats,
    csrf_token: &str,
    onion_address: Option<&str>,
) -> String {
    // Build a plain boards list for the nav bar
    let all_boards: Vec<Board> = board_stats.iter().map(|s| s.board.clone()).collect();

    let sfw: Vec<&crate::models::BoardStats> =
        board_stats.iter().filter(|s| !s.board.nsfw).collect();
    let nsfw: Vec<&crate::models::BoardStats> =
        board_stats.iter().filter(|s| s.board.nsfw).collect();

    fn board_cards(list: &[&crate::models::BoardStats]) -> String {
        list.iter()
            .map(|s| {
                let b = &s.board;
                let nsfw_badge = if b.nsfw {
                    r#"<span class="nsfw-badge">NSFW</span>"#
                } else {
                    ""
                };
                let thread_word = if s.thread_count == 1 {
                    "thread"
                } else {
                    "threads"
                };
                format!(
                    r#"<a class="board-card" href="/{sh}/catalog">
  <div class="board-card-short">/{sh}/</div>
  <div class="board-card-name">{n}{nsfw}</div>
  <div class="board-card-desc">{d}</div>
  <div class="board-card-stats">{tc} {tw}</div>
</a>"#,
                    sh = escape_html(&b.short_name),
                    n = escape_html(&b.name),
                    nsfw = nsfw_badge,
                    d = escape_html(&b.description),
                    tc = s.thread_count,
                    tw = thread_word,
                )
            })
            .collect()
    }

    let sfw_sec = if !sfw.is_empty() {
        format!("<div class=\"index-section\"><h2 class=\"index-section-title\">// Boards</h2><div class=\"board-cards\">{}</div></div>", board_cards(&sfw))
    } else {
        String::new()
    };

    let nsfw_sec = if !nsfw.is_empty() {
        format!("<div class=\"index-section\"><h2 class=\"index-section-title\">// Adult Boards <span class=\"nsfw-badge\">NSFW</span></h2><div class=\"board-cards\">{}</div></div>", board_cards(&nsfw))
    } else {
        String::new()
    };

    let empty = if board_stats.is_empty() {
        "<p class=\"index-empty\">no boards yet — admin must create boards first.</p>"
    } else {
        ""
    };

    let active_gb = site_stats.active_bytes as f64 / (1024.0 * 1024.0 * 1024.0);
    let stats_sec = format!(
        r#"<div class="index-section index-stats-section">
<h2 class="index-section-title">// Stats</h2>
<div class="index-stats-grid">
  <div class="index-stat"><span class="index-stat-value">{tp}</span><span class="index-stat-label">total posts</span></div>
  <div class="index-stat"><span class="index-stat-value">{ti}</span><span class="index-stat-label">images uploaded</span></div>
  <div class="index-stat"><span class="index-stat-value">{tv}</span><span class="index-stat-label">videos uploaded</span></div>
  <div class="index-stat"><span class="index-stat-value">{ta}</span><span class="index-stat-label">audio files uploaded</span></div>
  <div class="index-stat"><span class="index-stat-value">{gb:.2} GB</span><span class="index-stat-label">active content</span></div>
</div>
</div>"#,
        tp = site_stats.total_posts,
        ti = site_stats.total_images,
        tv = site_stats.total_videos,
        ta = site_stats.total_audio,
        gb = active_gb,
    );

    let onion_html = if let Some(addr) = onion_address {
        format!(
            r#"<div class="index-section index-onion-section">
<p class="index-onion"><code class="onion-addr">{}</code></p>
</div>"#,
            escape_html(addr)
        )
    } else {
        String::new()
    };

    let body = format!(
        r#"<div class="index-hero">
<h1 class="index-title">[ {name} ]</h1>
<p class="index-subtitle">{subtitle}</p>
</div>
{sfw}{nsfw}{empty}{stats}{onion}"#,
        name = escape_html(&live_site_name()),
        subtitle = escape_html(&live_site_subtitle()),
        sfw = sfw_sec,
        nsfw = nsfw_sec,
        empty = empty,
        stats = stats_sec,
        onion = onion_html,
    );

    base_layout(
        &live_site_name(),
        None,
        &body,
        csrf_token,
        &all_boards,
        false,
        false,
    )
}

// ─── Board index ──────────────────────────────────────────────────────────────

#[allow(clippy::too_many_arguments)]
pub fn board_page(
    board: &Board,
    summaries: &[ThreadSummary],
    pagination: &Pagination,
    csrf_token: &str,
    boards: &[Board],
    is_admin: bool,
    error: Option<&str>,
    collapse_greentext: bool,
) -> String {
    let mut body = String::new();

    // Inline error banner (e.g. validation failures on post submission)
    if let Some(msg) = error {
        body.push_str(&format!(
            r#"<div class="post-error-banner">&#9888; {}</div>"#,
            escape_html(msg)
        ));
    }

    // Visible admin toolbar — appears whenever an admin is logged in
    if is_admin {
        body.push_str(&format!(
            r#"<div class="admin-toolbar">
<span class="admin-toolbar-label">&#9632; ADMIN</span>
<form method="POST" action="/admin/logout" style="display:inline">
<input type="hidden" name="_csrf" value="{csrf}">
<input type="hidden" name="return_to" value="/{board}/">
<button type="submit" class="admin-toolbar-btn">logout</button>
</form>
</div>"#,
            csrf = escape_html(csrf_token),
            board = escape_html(&board.short_name),
        ));
    }

    {
        let short = escape_html(&board.short_name);
        let name = escape_html(&board.name);
        let desc = escape_html(&board.description);
        let nav_archive = if board.allow_archive {
            format!(r#"<a class="board-nav-link" href="/{short}/archive">[Archive]</a>"#)
        } else {
            String::new()
        };
        body.push_str(&format!(
            r#"<div class="board-header board-index-header"><h1>/{short}/  — {name}</h1><p class="board-desc">{desc}</p></div>
<div class="board-nav"><a class="board-nav-link active" href="/{short}/">[Index]</a><a class="board-nav-link" href="/{short}/catalog">[Catalog]</a>{nav_archive}</div>"#,
        ));
    }

    body.push_str(&format!(
        r#"<div class="post-toggle-bar centered catalog-toggle-bar">
  <button class="post-toggle-btn" data-action="toggle-post-form">[ Post a New Thread ]</button>
</div>
<div class="post-form-wrap" id="post-form-wrap" style="display:none">
  {}
</div>"#,
        new_thread_form(&board.short_name, csrf_token, board),
    ));

    for summary in summaries {
        body.push_str(&render_thread_summary(
            summary,
            &board.short_name,
            csrf_token,
            is_admin,
        ));
    }

    body.push_str(&render_pagination(
        pagination,
        &format!("/{}/", board.short_name),
    ));

    body.push_str(TOGGLE_SCRIPT);
    body.push_str(&compress_modal_script(
        crate::config::CONFIG.max_image_size,
        crate::config::CONFIG.max_video_size,
    ));

    base_layout(
        &format!("/{}/", board.short_name),
        Some(&board.short_name),
        &body,
        csrf_token,
        boards,
        collapse_greentext,
        board.allow_archive,
    )
}

fn new_thread_form(board_short: &str, csrf_token: &str, board: &Board) -> String {
    let image_mb = crate::config::CONFIG.max_image_size / 1024 / 1024;
    let video_mb = crate::config::CONFIG.max_video_size / 1024 / 1024;
    let audio_mb = crate::config::CONFIG.max_audio_size / 1024 / 1024;

    // PoW CAPTCHA block — only rendered when the board has it enabled.
    // The JS miner runs on page load, solving in the background. The nonce
    // field starts empty and is filled when a solution is found.
    // FIX[NEW-H1]: PoW config is passed via data-pow-board / data-pow-difficulty
    // attributes on the nonce input so main.js can start the solver without any
    // inline <script> block.
    let captcha_row = if board.allow_captcha {
        let difficulty: u32 = crate::utils::crypto::POW_DIFFICULTY;
        format!(
            r#"    <tr id="captcha-row-{b}"><td>captcha</td>
        <td>
          <span id="captcha-status-{b}" style="font-size:0.8rem;color:var(--text-dim)">solving proof-of-work… (this takes a moment)</span>
          <input type="hidden" name="pow_nonce" id="pow-nonce-{b}" value=""
                 data-pow-board="{b}" data-pow-difficulty="{diff}">
        </td></tr>"#,
            b = escape_html(board_short),
            diff = difficulty,
        )
    } else {
        String::new()
    };

    // FIX[NEW-H1]: captcha_js script block removed. The PoW solver now lives
    // entirely in /static/main.js, reading board name and difficulty from the
    // data-pow-board / data-pow-difficulty attributes set above.
    let captcha_js = String::new();

    // Show the secondary audio input only when the board allows both images and audio.
    let audio_combo_row = if board.allow_images && board.allow_audio {
        format!(
            r#"    <tr><td>audio<br><span style="font-size:0.65rem;color:var(--text-dim)">(+ image)</span></td>
        <td><input type="file" name="audio_file" accept="audio/mpeg,audio/ogg,audio/flac,audio/wav,audio/mp4,audio/aac,audio/webm,.mp3,.ogg,.flac,.wav,.m4a,.aac">
            <span style="font-size:0.72rem;color:var(--text-dim)">optional audio alongside image · max {audio_mb} MiB</span></td></tr>"#,
            audio_mb = audio_mb,
        )
    } else {
        String::new()
    };

    let edit_token_row = if board.allow_editing {
        r#"    <tr><td>edit token</td>
        <td><input type="text" name="deletion_token" placeholder="optional — lets you edit post" maxlength="64"><span style="font-size:0.72rem;color:var(--text-dim)"> keep it secret</span></td></tr>"#
    } else {
        ""
    };

    format!(
        r#"<div class="post-form-container">
<div class="post-form-title">[ new thread ]</div>
<form class="post-form" method="POST" action="/{board}/" enctype="multipart/form-data">
  <input type="hidden" name="_csrf" value="{csrf}">
  <table>
    <tr><td>name</td>
        <td><input type="text" name="name" placeholder="Anonymous" maxlength="64"></td></tr>
    <tr><td>subject</td>
        <td><input type="text" name="subject" maxlength="128">
            <button type="submit">post thread</button></td></tr>
    <tr><td>body</td>
        <td><textarea name="body" rows="5" maxlength="4096"></textarea>
            <div class="markup-hint">
              <span title="Greentext">&#62;green</span>
              <span title="Bold">**bold**</span>
              <span title="Italic">__italic__</span>
              <span title="Spoiler">[spoiler]text[/spoiler]</span>
              <span title="Reply">&gt;&gt;123</span>
              <span title="Cross-thread">&gt;&gt;&gt;/b/123</span>
              <span title="Emoji">:fire:</span>
            </div>
        </td></tr>
    <tr><td>file</td>
        <td><input type="file" name="file" data-onchange-check-size="1" accept="image/jpeg,image/png,image/gif,image/webp,video/mp4,video/webm,audio/mpeg,audio/ogg,audio/flac,audio/wav,audio/mp4,audio/aac,audio/webm,.mp3,.ogg,.flac,.wav,.m4a,.aac">
            <span style="font-size:0.72rem;color:var(--text-dim)">jpg/png/gif/webp · max {image_mb} MiB &nbsp;|&nbsp; mp4/webm · max {video_mb} MiB &nbsp;|&nbsp; mp3/ogg/flac/wav/m4a · max {audio_mb} MiB</span></td></tr>
    {audio_combo_row}
    {edit_token_row}
    {captcha_row}
    <tr><td colspan="2">
      <details class="poll-creator">
        <summary>[ 📊 Add a Poll to this thread ]</summary>
        <div class="poll-creator-inner">
          <div class="poll-creator-row">
            <label>Question<input type="text" name="poll_question" placeholder="What do you think?" maxlength="256"></label>
          </div>
          <div id="poll-options-list">
            <div class="poll-option-row"><input type="text" name="poll_option" placeholder="Option 1" maxlength="128"><button type="button" class="poll-remove-btn" data-action="remove-poll-option" style="display:none">✕</button></div>
            <div class="poll-option-row"><input type="text" name="poll_option" placeholder="Option 2" maxlength="128"><button type="button" class="poll-remove-btn" data-action="remove-poll-option" style="display:none">✕</button></div>
          </div>
          <button type="button" class="poll-add-btn" data-action="add-poll-option">+ Add Option</button>
          <div class="poll-creator-row poll-duration-row">
            <label>Duration
              <input type="number" name="poll_duration_value" value="24" min="1" max="720" class="poll-duration-input">
              <select name="poll_duration_unit" class="poll-duration-unit">
                <option value="hours">Hours</option>
                <option value="minutes">Minutes</option>
              </select>
            </label>
          </div>
        </div>
      </details>
    </td></tr>
  </table>
</form>
</div>
"#,
        // FIX[NEW-H1]: poll scripts moved to /static/main.js
        board = escape_html(board_short),
        csrf = escape_html(csrf_token),
        image_mb = image_mb,
        video_mb = video_mb,
        audio_mb = audio_mb,
        audio_combo_row = audio_combo_row,
        edit_token_row = edit_token_row,
        captcha_row = captcha_row,
    ) + &captcha_js
}

fn render_thread_summary(
    summary: &ThreadSummary,
    board_short: &str,
    csrf_token: &str,
    is_admin: bool,
) -> String {
    let t = &summary.thread;
    let mut html = String::new();

    let sticky_label = if t.sticky {
        r#"<span class="tag sticky">STICKY</span> "#
    } else {
        ""
    };
    let locked_label = if t.locked {
        r#"<span class="tag locked">LOCKED</span> "#
    } else {
        ""
    };

    html.push_str(&format!(
        r#"<div class="thread" id="t{tid}">
<div class="op post" id="p{op_id}">"#,
        tid = t.id,
        op_id = t.op_id.unwrap_or(0),
    ));

    if let (Some(_file), Some(thumb)) = (&t.op_file, &t.op_thumb) {
        html.push_str(&format!(
            r#"<div class="file-container"><a href="/{board}/thread/{tid}"><img class="thumb" src="/boards/{th}" loading="lazy" alt="image"></a></div>"#,
            board = escape_html(board_short),
            tid = t.id,
            th = escape_html(thumb),
        ));
    } else if let Some(embed_thumb) = t.op_body.as_deref().and_then(embed_thumb_from_body) {
        html.push_str(&format!(
            r#"<div class="file-container"><a href="/{board}/thread/{tid}"><img class="thumb embed-index-thumb" src="{src}" loading="lazy" alt="video thumbnail"></a></div>"#,
            board = escape_html(board_short),
            tid = t.id,
            src = escape_html(&embed_thumb),
        ));
    }

    html.push_str(&format!(
        r#"<div class="post-meta">
{sticky}{locked}
<strong class="name">{name}</strong>
<span class="post-time">{time}</span>
<a class="post-num" href="/{board}/thread/{tid}">No.{op_id}</a>
<a class="thread-id-link" href="/{board}/thread/{tid}" title="Thread #{tid}">[ #{tid} ]</a>
</div>"#,
        sticky = sticky_label,
        locked = locked_label,
        name = escape_html(t.op_name.as_deref().unwrap_or("Anonymous")),
        time = fmt_ts_short(t.created_at),
        board = escape_html(board_short),
        tid = t.id,
        op_id = t.op_id.unwrap_or(0),
    ));

    if let Some(subject) = &t.subject {
        html.push_str(&format!(
            r#"<div class="subject"><a href="/{b}/thread/{tid}"><strong>{s}</strong></a></div>"#,
            b = escape_html(board_short),
            tid = t.id,
            s = escape_html(subject),
        ));
    }

    if let Some(body) = &t.op_body {
        let truncated = if body.len() > 300 {
            format!(
                r#"{} <a href="/{b}/thread/{tid}">…[Read more]</a>"#,
                escape_html(&body[..300]),
                b = escape_html(board_short),
                tid = t.id,
            )
        } else {
            escape_html(body)
        };
        html.push_str(&format!(r#"<div class="post-body">{}</div>"#, truncated));
    }

    html.push_str(&format!(
        r#"<div class="thread-footer">
<a href="/{board}/thread/{tid}">[reply] ({n} {word})</a>"#,
        board = escape_html(board_short),
        tid = t.id,
        n = t.reply_count,
        word = if t.reply_count == 1 {
            "reply"
        } else {
            "replies"
        },
    ));

    // Admin: sticky/lock/delete controls on board index
    if is_admin {
        let sticky_act = if t.sticky { "unsticky" } else { "sticky" };
        let sticky_lbl = if t.sticky {
            "&#128204; unsticky"
        } else {
            "&#128204; sticky"
        };
        let lock_act = if t.locked { "unlock" } else { "lock" };
        let lock_lbl = if t.locked {
            "&#128275; unlock"
        } else {
            "&#128274; lock"
        };
        html.push_str(&format!(
            r#" <form method="POST" action="/admin/thread/action" style="display:inline">
<input type="hidden" name="_csrf"      value="{csrf}">
<input type="hidden" name="thread_id"  value="{tid}">
<input type="hidden" name="board"      value="{board}">
<input type="hidden" name="action"     value="{sticky_act}">
<button type="submit" class="admin-del-btn">{sticky_lbl}</button>
</form>
<form method="POST" action="/admin/thread/action" style="display:inline">
<input type="hidden" name="_csrf"      value="{csrf}">
<input type="hidden" name="thread_id"  value="{tid}">
<input type="hidden" name="board"      value="{board}">
<input type="hidden" name="action"     value="{lock_act}">
<button type="submit" class="admin-del-btn">{lock_lbl}</button>
</form>
<form method="POST" action="/admin/thread/delete" style="display:inline">
<input type="hidden" name="_csrf"      value="{csrf}">
<input type="hidden" name="thread_id"  value="{tid}">
<input type="hidden" name="board"      value="{board}">
<button type="submit" class="admin-del-btn"
        data-confirm="Delete thread No.{tid} and all its posts?">&#x2715; del</button>
</form>"#,
            csrf = escape_html(csrf_token),
            tid = t.id,
            board = escape_html(board_short),
            sticky_act = sticky_act,
            sticky_lbl = sticky_lbl,
            lock_act = lock_act,
            lock_lbl = lock_lbl,
        ));
    }

    html.push_str("</div>\n</div>");

    if summary.omitted > 0 {
        html.push_str(&format!(
            r#"<div class="omitted">{} posts omitted. <a href="/{b}/thread/{tid}">view thread</a></div>"#,
            summary.omitted,
            b = escape_html(board_short),
            tid = t.id,
        ));
    }

    for post in &summary.preview_posts {
        html.push_str(&render_post(
            post,
            board_short,
            csrf_token,
            false,
            is_admin,
            true,
            0, // no edit link on board index previews
        ));
    }

    html.push_str("<hr class=\"thread-sep\">");
    html
}

// ─── Thread page ──────────────────────────────────────────────────────────────

#[allow(clippy::too_many_arguments)]
pub fn thread_page(
    board: &Board,
    thread: &Thread,
    posts: &[Post],
    csrf_token: &str,
    boards: &[Board],
    is_admin: bool,
    poll: Option<&crate::models::PollData>,
    error: Option<&str>,
    collapse_greentext: bool,
) -> String {
    let mut body = String::new();

    // Inline error banner (e.g. validation failures on reply submission)
    if let Some(msg) = error {
        body.push_str(&format!(
            r#"<div class="post-error-banner">&#9888; {}</div>"#,
            escape_html(msg)
        ));
    }

    // Visible admin toolbar
    if is_admin {
        let sticky_action = if thread.sticky {
            ("unsticky", "&#128204; Unsticky")
        } else {
            ("sticky", "&#128204; Sticky")
        };
        let lock_action = if thread.locked {
            ("unlock", "&#128275; Unlock")
        } else {
            ("lock", "&#128274; Lock")
        };
        body.push_str(&format!(
            r#"<div class="admin-toolbar">
<span class="admin-toolbar-label">&#9632; ADMIN</span>
<form method="POST" action="/admin/thread/action" style="display:inline">
<input type="hidden" name="_csrf" value="{csrf}">
<input type="hidden" name="thread_id" value="{tid}">
<input type="hidden" name="action" value="{sticky_act}">
<input type="hidden" name="board" value="{board}">
<button type="submit" class="admin-toolbar-btn">{sticky_lbl}</button>
</form>
<form method="POST" action="/admin/thread/action" style="display:inline">
<input type="hidden" name="_csrf" value="{csrf}">
<input type="hidden" name="thread_id" value="{tid}">
<input type="hidden" name="action" value="{lock_act}">
<input type="hidden" name="board" value="{board}">
<button type="submit" class="admin-toolbar-btn">{lock_lbl}</button>
</form>
<form method="POST" action="/admin/thread/delete" style="display:inline">
<input type="hidden" name="_csrf" value="{csrf}">
<input type="hidden" name="thread_id" value="{tid}">
<input type="hidden" name="board" value="{board}">
<button type="submit" class="admin-toolbar-btn admin-toolbar-danger"
        data-confirm="Delete this entire thread and all its posts?">&#x2715; delete thread</button>
</form>
<form method="POST" action="/admin/logout" style="display:inline">
<input type="hidden" name="_csrf" value="{csrf}">
<input type="hidden" name="return_to" value="/{board}/thread/{tid}">
<button type="submit" class="admin-toolbar-btn">logout</button>
</form>
</div>"#,
            csrf = escape_html(csrf_token),
            tid = thread.id,
            board = escape_html(&board.short_name),
            sticky_act = sticky_action.0,
            sticky_lbl = sticky_action.1,
            lock_act = lock_action.0,
            lock_lbl = lock_action.1,
        ));
    }

    let locked_notice = if thread.locked {
        r#"<div class="notice locked-notice">this thread is locked — no new replies allowed</div>"#
    } else {
        ""
    };

    body.push_str(&format!(
        r##"<div class="thread-board-banner board-thread-header">/{s}/ — {bn}</div>
<div class="board-header thread-nav">
  <a href="/{s}/">[ Return ]</a>
  <a href="/{s}/catalog">[ Catalog ]</a>
  <a href="#bottom">[ Bottom ]</a>
  <button class="thread-nav-btn" data-action="fetch-updates">[ Update ]</button>
  <label class="autoupdate-label">
    <input type="checkbox" id="autoupdate-toggle-cb" data-action="autoupdate-toggle">
    Auto
  </label>
  <span class="autoupdate-status" id="autoupdate-status"></span>
  <span class="thread-reply-stat">R: <span id="thread-reply-count">{rc}</span></span>
</div>
"##,
        s = escape_html(&board.short_name),
        bn = escape_html(&board.name),
        rc = thread.reply_count,
    ));
    body.push_str(locked_notice);

    // Poll (anchored at #poll)
    if let Some(pd) = poll {
        body.push_str(&render_poll(pd, thread.id, &board.short_name, csrf_token));
    }

    // Container for live-updating posts — the auto-update script appends here.
    let last_post_id = posts.iter().map(|p| p.id).max().unwrap_or(0);
    body.push_str(&format!(
        r#"<div id="thread-posts" data-thread-id="{tid}" data-board="{board}" data-last-id="{last}">"#,
        tid   = thread.id,
        board = escape_html(&board.short_name),
        last  = last_post_id,
    ));
    for post in posts {
        body.push_str(&render_post(
            post,
            &board.short_name,
            csrf_token,
            true,
            is_admin,
            true,
            board.edit_window_secs,
        ));
    }

    // Close the posts container opened above
    body.push_str("</div><!-- #thread-posts -->\n");
    body.push_str("<div id=\"bottom\"></div>\n");

    if !thread.locked {
        let form_html = reply_form(&board.short_name, thread.id, csrf_token, board);
        body.push_str(&format!(
            r#"<div class="post-toggle-bar reply">
  <button class="post-toggle-btn" data-action="toggle-post-form">[ Reply ]</button>
</div>
<div class="post-form-wrap" id="post-form-wrap" style="display:none">
  {form}
</div>

<!-- Mobile sticky reply drawer — visible only on small screens via CSS -->
<div class="mobile-reply-fab" id="mobile-reply-fab" data-action="toggle-mobile-drawer">
  ✏ Reply
</div>
<div class="mobile-reply-drawer" id="mobile-reply-drawer">
  <div class="mobile-drawer-header">
    <span>reply to thread</span>
    <button class="mobile-drawer-close" data-action="toggle-mobile-drawer">✕</button>
  </div>
  <div class="mobile-drawer-body">
    {form}
  </div>
</div>"#,
            form = form_html,
        ));
    }

    body.push_str(TOGGLE_SCRIPT);
    body.push_str(&compress_modal_script(
        crate::config::CONFIG.max_image_size,
        crate::config::CONFIG.max_video_size,
    ));
    body.push_str(report_modal_script());
    body.push_str(thread_autoupdate_script());

    // FIX[NEW-H1]: Quotelink script moved to /static/main.js

    // ── Inline ban+delete prompt ───────────────────────────────────────────
    if is_admin {
        // FIX[NEW-H1]: adminBanDelete moved to /static/main.js

        // FIX[NEW-H1]: Cross-board quotelink script moved to /static/main.js
    } // end if is_admin

    // FIX[NEW-H1]: Cross-board quotelink + video embed + draft scripts moved to /static/main.js

    // ── Video embed unfurling (opt-in per board) ────────────────────────────
    // When enabled, .video-unfurl placeholder spans emitted by the markup parser
    // are replaced with a thumbnail + click-to-embed iframe widget matching the
    // webm/image layout — positioned before the post body, not inline with text.
    let embed_enabled = if board.allow_video_embeds {
        "true"
    } else {
        "false"
    };
    body.push_str(&format!(
        r#"<script>
(function() {{
  var EMBED_ENABLED = {embed_enabled};
  if (!EMBED_ENABLED) return;

  function buildEmbed(span) {{
    var type = span.getAttribute('data-embed-type');
    var id   = span.getAttribute('data-embed-id');
    var url  = span.getAttribute('data-url') || span.textContent.trim();
    if (!type || !id) return;

    // ── outer container: matches .file-container webm layout ─────────────
    var container = document.createElement('div');
    container.className = 'file-container video-embed-container';

    // ── file-info row (link + close button) ───────────────────────────────
    var info = document.createElement('div');
    info.className = 'file-info';
    var a = document.createElement('a');
    a.href = url; a.rel = 'nofollow noopener'; a.target = '_blank';
    a.textContent = url;
    var closeBtn = document.createElement('button');
    closeBtn.className = 'media-close-btn';
    closeBtn.innerHTML = '&#x2715; close';
    closeBtn.style.display = 'none';
    closeBtn.addEventListener('click', function(e) {{
      e.stopPropagation();
      collapseVideoEmbed(closeBtn);
    }});
    info.appendChild(a);
    info.appendChild(closeBtn);
    container.appendChild(info);

    // ── thumbnail preview (styled like webm .media-preview) ───────────────
    var preview = document.createElement('div');
    preview.className = 'media-preview';
    preview.title = 'click to play';

    if (type === 'youtube') {{
      var img = document.createElement('img');
      img.className = 'thumb';
      img.loading = 'lazy';
      img.alt = 'video thumbnail';
      // Use mqdefault (320×180) — reliable across all videos, no black bars
      img.src = 'https://img.youtube.com/vi/' + id + '/mqdefault.jpg';
      preview.appendChild(img);
    }} else if (type === 'streamable') {{
      var ph = document.createElement('div');
      ph.className = 'thumb embed-placeholder-thumb';
      ph.innerHTML = '&#9654; streamable';
      preview.appendChild(ph);
    }}

    var overlay = document.createElement('div');
    overlay.className = 'media-expand-overlay';
    overlay.innerHTML = '&#9654;';
    preview.appendChild(overlay);

    preview.addEventListener('click', function() {{
      expandVideoEmbed(preview, type, id, container);
    }});
    container.appendChild(preview);

    // ── move container before the post-body, remove span from body text ───
    var postBody = span.closest('.post-body');
    if (postBody && postBody.parentNode) {{
      span.remove();
      postBody.parentNode.insertBefore(container, postBody);
    }} else {{
      span.replaceWith(container);
    }}
  }}

  function applyEmbeds(root) {{
    root.querySelectorAll('span.video-unfurl[data-embed-type]').forEach(buildEmbed);
  }}

  applyEmbeds(document);

  var _origEmbed = window._onNewPostsInserted;
  window._onNewPostsInserted = function(container) {{
    if (_origEmbed) _origEmbed(container);
    applyEmbeds(container);
  }};
}})();
</script>"#,
        embed_enabled = embed_enabled
    ));

    // Draft autosave
    let draft_key = format!("rustchan_draft_{}_{}", board.short_name, thread.id);
    let draft_key_debug = format!("{:?}", draft_key);
    body.push_str(&format!(
        r#"<script>
(function() {{
  var DRAFT_KEY = {key};
  var ta = document.getElementById('reply-body');
  if (!ta) return;

  // Restore draft on load
  try {{
    var saved = localStorage.getItem(DRAFT_KEY);
    if (saved) {{ ta.value = saved; }}
  }} catch(e) {{}}

  // Autosave every 3 seconds
  setInterval(function() {{
    try {{ localStorage.setItem(DRAFT_KEY, ta.value); }} catch(e) {{}}
  }}, 3000);

  // Clear draft when the reply form is submitted
  var form = ta.closest('form');
  if (form) {{
    form.addEventListener('submit', function() {{
      try {{ localStorage.removeItem(DRAFT_KEY); }} catch(e) {{}}
    }});
  }}
}})();
</script>"#,
        key = draft_key_debug,
    ));

    base_layout(
        &format!(
            "/{}/  {}",
            board.short_name,
            thread.subject.as_deref().unwrap_or("thread")
        ),
        Some(&board.short_name),
        &body,
        csrf_token,
        boards,
        collapse_greentext,
        board.allow_archive,
    )
}

// ─── Poll renderer ────────────────────────────────────────────────────────────

fn render_poll(
    pd: &crate::models::PollData,
    thread_id: i64,
    board_short: &str,
    csrf_token: &str,
) -> String {
    let now = chrono::Utc::now().timestamp();
    let time_left = pd.poll.expires_at - now;
    let expires_str = if pd.is_expired {
        "closed".to_string()
    } else if time_left < 3600 {
        format!("closes in {}m", time_left / 60)
    } else if time_left < 86400 {
        format!(
            "closes in {}h {}m",
            time_left / 3600,
            (time_left % 3600) / 60
        )
    } else {
        format!("closes {}", fmt_ts(pd.poll.expires_at))
    };

    let show_results = pd.is_expired || pd.user_voted_option.is_some();

    let mut html = format!(
        r#"<div class="poll-container">
<div class="poll-header">
  <span class="poll-icon">📊</span>
  <span class="poll-question">{q}</span>
  <span class="poll-status {status_class}">[{expires}]</span>
</div>"#,
        q = escape_html(&pd.poll.question),
        status_class = if pd.is_expired {
            "poll-closed"
        } else {
            "poll-open"
        },
        expires = expires_str,
    );

    if show_results {
        // Results view
        let total = pd.total_votes.max(1);
        html.push_str(r#"<div class="poll-results">"#);
        for opt in &pd.options {
            let pct = (opt.vote_count as f64 / total as f64 * 100.0).round() as i64;
            let is_voted = pd.user_voted_option == Some(opt.id);
            html.push_str(&format!(
                r#"<div class="poll-option-result{voted}">
  <div class="poll-option-label">
    {check}<span class="poll-opt-text">{text}</span>
    <span class="poll-opt-count">{votes} ({pct}%)</span>
  </div>
  <div class="poll-bar-track"><div class="poll-bar-fill" style="width:{pct}%"></div></div>
</div>"#,
                voted = if is_voted { " user-voted" } else { "" },
                check = if is_voted { "✓ " } else { "" },
                text = escape_html(&opt.text),
                votes = opt.vote_count,
                pct = pct,
            ));
        }
        html.push_str(&format!(
            r#"<div class="poll-total">{} total vote{}</div></div>"#,
            pd.total_votes,
            if pd.total_votes == 1 { "" } else { "s" },
        ));
    } else {
        // Voting form
        html.push_str(&format!(
            r#"<form class="poll-vote-form" method="POST" action="/vote">
<input type="hidden" name="_csrf"     value="{csrf}">
<input type="hidden" name="thread_id" value="{tid}">
<input type="hidden" name="board"     value="{board}">"#,
            csrf = escape_html(csrf_token),
            tid = thread_id,
            board = escape_html(board_short),
        ));
        for opt in &pd.options {
            html.push_str(&format!(
                r#"<label class="poll-vote-option">
  <input type="radio" name="option_id" value="{id}" required>
  <span class="poll-opt-text">{text}</span>
</label>"#,
                id = opt.id,
                text = escape_html(&opt.text),
            ));
        }
        html.push_str(
            r#"<button type="submit" class="poll-vote-btn">[ Cast Vote ]</button></form>"#,
        );
    }

    html.push_str("</div>");
    html
}

pub fn render_post(
    post: &Post,
    board_short: &str,
    csrf_token: &str,
    show_delete: bool,
    is_admin: bool,
    show_media: bool,
    edit_window_secs: i64,
) -> String {
    let tripcode_html = post
        .tripcode
        .as_ref()
        .map(|t| format!(r#"<span class="tripcode">!{}</span>"#, escape_html(t)))
        .unwrap_or_default();

    // "edited" badge — shown when the post body was modified after creation.
    let edited_html = post
        .edited_at
        .map(|ts| {
            format!(
                r#" <span class="post-edited" title="last edited {full}">(edited {short})</span>"#,
                full = fmt_ts(ts),
                short = fmt_ts_short(ts),
            )
        })
        .unwrap_or_default();

    let op_class = if post.is_op { " op" } else { " reply" };

    let mut html = format!(
        r##"<div class="post{op_class}" id="p{id}">
<div class="post-meta">
<strong class="name">{name}</strong>{tripcode}
<span class="post-time">{time}</span>{edited}
<a class="post-num" href="#p{id}" data-action="append-reply" data-id="{id}">No.{id}</a>
<span class="backrefs" id="backrefs-{id}"></span>
</div>"##,
        op_class = op_class,
        id = post.id,
        name = escape_html(&post.name),
        tripcode = tripcode_html,
        time = fmt_ts_short(post.created_at),
        edited = edited_html,
    );

    if let Some(subject) = &post.subject {
        html.push_str(&format!(
            r#"<div class="subject"><strong>{}</strong></div>"#,
            escape_html(subject)
        ));
    }

    // Image / Video / Audio — uses flex layout so text wraps naturally at any size
    if show_media {
        if let (Some(file), Some(thumb)) = (&post.file_path, &post.thumb_path) {
            let size_str = post.file_size.map(format_file_size).unwrap_or_default();
            let name_str = post.file_name.as_deref().unwrap_or("file");
            let mime = post
                .mime_type
                .as_deref()
                .unwrap_or("application/octet-stream");
            // Use explicit media_type when available; fall back to MIME prefix sniff.
            let is_audio = matches!(&post.media_type, Some(crate::models::MediaType::Audio))
                || post
                    .mime_type
                    .as_deref()
                    .map(|m| m.starts_with("audio/"))
                    .unwrap_or(false);
            let is_video = !is_audio
                && (matches!(&post.media_type, Some(crate::models::MediaType::Video))
                    || post
                        .mime_type
                        .as_deref()
                        .map(|m| m.starts_with("video/"))
                        .unwrap_or(false));

            if is_audio {
                // ── Audio player ─────────────────────────────────────────────────
                // Rendered with <audio controls preload="none"> for zero auto-load.
                // The waveform PNG (or SVG placeholder) is shown above the player.
                html.push_str(&format!(
                    r#"<div class="file-container audio-container">
<div class="file-info">
  <a href="/boards/{f}">{orig}</a> ({sz})
</div>
<div class="audio-thumb">
  <img class="thumb" src="/boards/{th}" loading="lazy" alt="audio">
</div>
<audio controls preload="none" class="audio-player">
  <source src="/boards/{f}" type="{mime}">
  Your browser does not support the audio element.
</audio>
</div>"#,
                    f = escape_html(file),
                    th = escape_html(thumb),
                    orig = escape_html(name_str),
                    sz = escape_html(&size_str),
                    mime = escape_html(mime),
                ));
            } else if is_video {
                html.push_str(&format!(
                r#"<div class="file-container">
<div class="file-info">
  <a href="/boards/{f}">{orig}</a> ({sz})
  <button class="media-close-btn" data-action="collapse-media" style="display:none">&#x2715; close</button>
</div>
<div class="media-preview" data-action="expand-media" title="click to play">
  <img class="thumb" src="/boards/{th}" loading="lazy" alt="video thumbnail">
  <div class="media-expand-overlay">&#9654;</div>
</div>
<video class="media-expanded" controls preload="none" style="display:none">
  <source src="/boards/{f}" type="{mime}">
</video>
</div>"#,
                f = escape_html(file),
                th = escape_html(thumb),
                orig = escape_html(name_str),
                sz = escape_html(&size_str),
                mime = escape_html(mime),
            ));
            } else {
                html.push_str(&format!(
                r#"<div class="file-container">
<div class="file-info">
  <a href="/boards/{f}">{orig}</a> ({sz})
  <button class="media-close-btn" data-action="collapse-media" style="display:none">&#x2715; close</button>
</div>
<div class="media-preview" data-action="expand-media" title="click to expand">
  <img class="thumb" src="/boards/{th}" loading="lazy" alt="image">
  <div class="media-expand-overlay">&#x2922;</div>
</div>
<img class="media-expanded" src="" data-src="/boards/{f}" style="display:none"
     alt="image" draggable="false">
</div>"#,
                f = escape_html(file),
                th = escape_html(thumb),
                orig = escape_html(name_str),
                sz = escape_html(&size_str),
            ));
            }
        }
    } // end show_media

    // ── Secondary audio for image+audio combo posts ───────────────────────────
    if show_media {
        if let (Some(aud_file), Some(aud_mime)) = (&post.audio_file_path, &post.audio_mime_type) {
            let aud_name = post.audio_file_name.as_deref().unwrap_or("audio");
            let aud_size = post
                .audio_file_size
                .map(format_file_size)
                .unwrap_or_default();
            html.push_str(&format!(
                r#"<div class="file-container audio-container audio-combo">
<div class="file-info">
  <a href="/boards/{f}">{orig}</a> ({sz})
</div>
<audio controls preload="none" class="audio-player">
  <source src="/boards/{f}" type="{mime}">
  Your browser does not support the audio element.
</audio>
</div>"#,
                f = escape_html(aud_file),
                orig = escape_html(aud_name),
                sz = escape_html(&aud_size),
                mime = escape_html(aud_mime),
            ));
        }
    }

    // Post body (pre-rendered, sanitised HTML)
    html.push_str(&format!(
        r#"<div class="post-body">{}</div>"#,
        post.body_html
    ));

    // Edit link + report button (only on thread pages where show_delete=true)
    if show_delete {
        let now = chrono::Utc::now().timestamp();
        let within_edit_window = edit_window_secs > 0 && now - post.created_at <= edit_window_secs;
        let edit_link = if within_edit_window {
            format!(
                r#" <a class="edit-btn" href="/{board}/post/{pid}/edit" title="Edit post">edit</a>"#,
                board = escape_html(board_short),
                pid = post.id,
            )
        } else {
            String::new()
        };

        // Report button — opens the shared report modal with this post's data.
        let report_btn = format!(
            r#" <button type="button" class="report-btn"
                data-action="open-report" data-pid="{pid}" data-tid="{tid}" data-board="{board}" data-csrf="{csrf}">report</button>"#,
            pid = post.id,
            tid = post.thread_id,
            board = escape_html(board_short),
            csrf = escape_html(csrf_token),
        );

        html.push_str(&format!(
            r#"<div class="post-controls">{edit_link}{report_btn}</div>"#,
            edit_link = edit_link,
            report_btn = report_btn,
        ));
    }

    // Admin delete button + IP history link + inline ban+delete — shown whenever admin is logged in
    if is_admin {
        let is_op_val = if post.is_op { "1" } else { "0" };
        html.push_str(&format!(
            r#"<div class="post-controls admin-post-controls">
<form method="POST" action="/admin/post/delete">
<input type="hidden" name="_csrf"   value="{csrf}">
<input type="hidden" name="post_id" value="{pid}">
<input type="hidden" name="board"   value="{board}">
<button type="submit" class="admin-del-btn"
        data-confirm="Admin delete post No.{pid}?">&#x2715; del</button>
</form>
<form method="POST" action="/admin/post/ban-delete"
      data-ban-delete-pid="{pid}">
<input type="hidden" name="_csrf"      value="{csrf}">
<input type="hidden" name="post_id"    value="{pid}">
<input type="hidden" name="ip_hash"    value="{ip_hash}">
<input type="hidden" name="board"      value="{board}">
<input type="hidden" name="thread_id"  value="{tid}">
<input type="hidden" name="is_op"      value="{is_op}">
<input type="hidden" name="reason"     id="ban-reason-{pid}" value="">
<input type="hidden" name="duration_hours" id="ban-dur-{pid}" value="0">
<button type="submit" class="admin-del-btn btn-danger">&#x26D4; ban+del</button>
</form>
<a class="admin-ip-link" href="/admin/ip/{ip_hash}" title="View all posts from this IP hash">&#x1F50D; ip</a>
</div>"#,
            csrf    = escape_html(csrf_token),
            pid     = post.id,
            board   = escape_html(board_short),
            ip_hash = escape_html(&post.ip_hash),
            tid     = post.thread_id,
            is_op   = is_op_val,
        ));
    }

    html.push_str("</div>\n");
    html
}

fn reply_form(board_short: &str, thread_id: i64, csrf_token: &str, board: &Board) -> String {
    let image_mb = crate::config::CONFIG.max_image_size / 1024 / 1024;
    let video_mb = crate::config::CONFIG.max_video_size / 1024 / 1024;
    let audio_mb = crate::config::CONFIG.max_audio_size / 1024 / 1024;

    // Build the accept attribute and hint for the primary file input
    // based on which media types are enabled for this board.
    let mut accept_parts: Vec<&str> = Vec::new();
    let mut hint_parts: Vec<String> = Vec::new();
    if board.allow_images {
        accept_parts.push("image/jpeg,image/png,image/gif,image/webp");
        hint_parts.push(format!("jpg/png/gif/webp · max {} MiB", image_mb));
    }
    if board.allow_video {
        accept_parts.push("video/mp4,video/webm");
        hint_parts.push(format!("mp4/webm · max {} MiB", video_mb));
    }
    if board.allow_audio {
        accept_parts.push("audio/mpeg,audio/ogg,audio/flac,audio/wav,audio/mp4,audio/aac,audio/webm,.mp3,.ogg,.flac,.wav,.m4a,.aac");
        hint_parts.push(format!("mp3/ogg/flac/wav/m4a · max {} MiB", audio_mb));
    }
    let file_accept = accept_parts.join(",");
    let file_hint = hint_parts.join(" &nbsp;|&nbsp; ");

    // The secondary audio-alongside-image row is only shown when both
    // images and audio are enabled.
    let audio_combo_row = if board.allow_images && board.allow_audio {
        format!(
            r#"    <tr><td>audio<br><span style="font-size:0.65rem;color:var(--text-dim)">(+ image)</span></td>
        <td><input type="file" name="audio_file" accept="audio/mpeg,audio/ogg,audio/flac,audio/wav,audio/mp4,audio/aac,audio/webm,.mp3,.ogg,.flac,.wav,.m4a,.aac">
            <span style="font-size:0.72rem;color:var(--text-dim)">optional audio alongside image · max {audio_mb} MiB</span></td></tr>"#,
            audio_mb = audio_mb,
        )
    } else {
        String::new()
    };

    let edit_token_row = if board.allow_editing {
        r#"    <tr><td>edit token</td>
        <td><input type="text" name="deletion_token" placeholder="optional — lets you edit post" maxlength="64"><span style="font-size:0.72rem;color:var(--text-dim)"> keep it secret</span></td></tr>"#
    } else {
        ""
    };

    format!(
        r#"<div class="post-form-container reply-form-container">
<div class="post-form-title">[ reply to thread ]</div>
<form class="post-form" method="POST" action="/{board}/thread/{tid}" enctype="multipart/form-data">
  <input type="hidden" name="_csrf" value="{csrf}">
  <table>
    <tr><td>name</td>
        <td><input type="text" name="name" placeholder="Anonymous" maxlength="64"></td></tr>
    <tr><td>body</td>
        <td><textarea id="reply-body" name="body" rows="4" maxlength="4096"></textarea>
            <button type="submit">post reply</button></td></tr>
    <tr><td>file</td>
        <td><input type="file" name="file" data-onchange-check-size="1" accept="{file_accept}">
            <span style="font-size:0.72rem;color:var(--text-dim)">{file_hint}</span></td></tr>
{audio_combo_row}    <tr><td>options</td>
        <td><label class="sage-label"><input type="checkbox" name="sage" value="1"> sage <span class="sage-hint">(don&apos;t bump thread)</span></label></td></tr>
    {edit_token_row}
  </table>
</form>
</div>"#,
        board = escape_html(board_short),
        tid = thread_id,
        csrf = escape_html(csrf_token),
        file_accept = file_accept,
        file_hint = file_hint,
        audio_combo_row = audio_combo_row,
        edit_token_row = edit_token_row,
    )
}

// ─── Catalog page ─────────────────────────────────────────────────────────────

pub fn catalog_page(
    board: &Board,
    threads: &[Thread],
    csrf_token: &str,
    boards: &[Board],
    is_admin: bool,
    collapse_greentext: bool,
) -> String {
    let bs = escape_html(&board.short_name);
    let bn = escape_html(&board.name);

    let mut body = String::new();

    // Visible admin toolbar — appears whenever an admin is logged in
    if is_admin {
        body.push_str(&format!(
            r#"<div class="admin-toolbar">
<span class="admin-toolbar-label">&#9632; ADMIN</span>
<form method="POST" action="/admin/logout" style="display:inline">
<input type="hidden" name="_csrf" value="{csrf}">
<input type="hidden" name="return_to" value="/{board}/catalog">
<button type="submit" class="admin-toolbar-btn">logout</button>
</form>
</div>"#,
            csrf = escape_html(csrf_token),
            board = escape_html(&board.short_name),
        ));
    }

    let nav_archive = if board.allow_archive {
        format!(r#"<a class="board-nav-link" href="/{bs}/archive">[Archive]</a>"#)
    } else {
        String::new()
    };

    body.push_str(&format!(
        r#"<div class="board-header catalog-header-row">
  <div class="catalog-header-left board-catalog-header">
    <h1>/{bs}/  — {bn}</h1>
    <p class="board-desc">{desc}</p>
  </div>
  <div class="catalog-sort-wrap">
    <label class="catalog-sort-label" for="catalog-sort">sort:</label>
    <select id="catalog-sort" class="catalog-sort-select" data-action="sort-catalog">
      <option value="bump" selected>bump order</option>
      <option value="replies">reply count</option>
      <option value="created">creation date</option>
      <option value="last_reply">last reply</option>
    </select>
  </div>
</div>
<div class="board-nav"><a class="board-nav-link" href="/{bs}/">[Index]</a><a class="board-nav-link active" href="/{bs}/catalog">[Catalog]</a>{nav_archive}</div>
<div class="post-toggle-bar centered catalog-toggle-bar">
  <button class="post-toggle-btn" data-action="toggle-post-form">[ Start a New Thread ]</button>
</div>
<div class="post-form-wrap" id="post-form-wrap" style="display:none">
  {form}
</div>
<div class="catalog-grid" id="catalog-grid">"#,
        bs = bs,
        bn = bn,
        desc = escape_html(&board.description),
        nav_archive = nav_archive,
        form = new_thread_form(&board.short_name, csrf_token, board),
    ));

    for t in threads {
        let thumb_html = if let Some(th) = &t.op_thumb {
            format!(
                r#"<img class="catalog-thumb" src="/boards/{}" loading="lazy" alt="">"#,
                escape_html(th)
            )
        } else if let Some(embed_thumb) = t.op_body.as_deref().and_then(embed_thumb_from_body) {
            format!(
                r#"<img class="catalog-thumb embed-catalog-thumb" src="{}" loading="lazy" alt="video thumbnail">"#,
                escape_html(&embed_thumb)
            )
        } else {
            r#"<div class="catalog-no-image">no img</div>"#.to_string()
        };

        let subject = t
            .subject
            .as_deref()
            .unwrap_or_else(|| t.op_body.as_deref().unwrap_or(""));
        let preview: String = subject.chars().take(80).collect();

        body.push_str(&format!(
            r#"<div class="catalog-item{sticky}" data-replies="{replies}" data-created="{created}" data-bumped="{bumped}" data-sticky="{is_sticky}">
<a href="/{board}/thread/{tid}">
{thumb}
<div class="catalog-info">
<span class="catalog-replies">R: {replies} / F: {images}</span>
<p class="catalog-subject">{subj}</p>
</div>
</a>
</div>"#,
            sticky = if t.sticky { " sticky" } else { "" },
            is_sticky = if t.sticky { "1" } else { "0" },
            board = escape_html(&board.short_name),
            tid = t.id,
            thumb = thumb_html,
            replies = t.reply_count,
            images = t.image_count,
            subj = escape_html(&preview),
            created = t.created_at,
            bumped = t.bumped_at,
        ));
    }

    body.push_str("</div>");
    // FIX[NEW-H1]: sortCatalog moved to /static/main.js
    body.push_str(TOGGLE_SCRIPT);
    body.push_str(&compress_modal_script(
        crate::config::CONFIG.max_image_size,
        crate::config::CONFIG.max_video_size,
    ));
    base_layout(
        &format!("/{}/  catalog", board.short_name),
        Some(&board.short_name),
        &body,
        csrf_token,
        boards,
        collapse_greentext,
        board.allow_archive,
    )
}

// ─── Search results ───────────────────────────────────────────────────────────

pub fn search_page(
    board: &Board,
    query: &str,
    posts: &[Post],
    pagination: &Pagination,
    csrf_token: &str,
    boards: &[Board],
    collapse_greentext: bool,
) -> String {
    let mut body = format!(
        r#"<div class="page-box">
<h2 style="color:var(--green-pale);font-size:0.9rem;margin-bottom:8px">search: "{}" in /{}/</h2>
<form method="GET" action="/{}/search">
  <input type="text" name="q" value="{}" maxlength="64" style="background:var(--bg-input);border:1px solid var(--border);color:var(--green-pale);padding:4px 8px;font-family:var(--font)">
  <button type="submit">search</button>
</form>"#,
        escape_html(query),
        escape_html(&board.short_name),
        escape_html(&board.short_name),
        escape_html(query),
    );

    if posts.is_empty() {
        body.push_str(r#"<p style="color:var(--text-dim);margin-top:8px">no results found.</p>"#);
    } else {
        body.push_str(&format!(
            r#"<p style="color:var(--text-dim);font-size:0.8rem;margin-top:6px">{} result(s)</p>"#,
            pagination.total
        ));
        for post in posts {
            body.push_str(&render_post(
                post,
                &board.short_name,
                csrf_token,
                false,
                false,
                true,
                0, // no edit link on search results
            ));
        }
        body.push_str(&render_pagination(
            pagination,
            &format!(
                "/{}/search?q={}",
                board.short_name,
                urlencoding_simple(query)
            ),
        ));
    }

    body.push_str("</div>");
    base_layout(
        &format!("search — /{}/", board.short_name),
        Some(&board.short_name),
        &body,
        csrf_token,
        boards,
        collapse_greentext,
        board.allow_archive,
    )
}

pub fn archive_page(
    board: &Board,
    threads: &[Thread],
    pagination: &Pagination,
    csrf_token: &str,
    boards: &[Board],
    collapse_greentext: bool,
) -> String {
    let bs = escape_html(&board.short_name);
    let bn = escape_html(&board.name);

    let mut body = format!(
        r#"<div class="board-header board-index-header"><h1>/{bs}/  — {bn}</h1><p class="board-desc">{desc}</p></div>
<div class="board-nav">
  <a class="board-nav-link" href="/{bs}/">[Index]</a>
  <a class="board-nav-link" href="/{bs}/catalog">[Catalog]</a>
  <a class="board-nav-link active" href="/{bs}/archive">[Archive]</a>
</div>
<div class="page-box">
<p class="archive-subtext">Threads cycled off the board index — read-only, preserved permanently.</p>
</div>"#,
        bs = bs,
        bn = bn,
        desc = escape_html(&board.description),
    );

    if threads.is_empty() {
        body.push_str(
            r#"<div class="page-box"><p style="color:var(--text-dim)">no archived threads yet.</p></div>"#,
        );
    } else {
        body.push_str(r#"<div class="archive-list">"#);
        for t in threads {
            let preview: String = t
                .op_body
                .as_deref()
                .unwrap_or("")
                .chars()
                .take(120)
                .collect();
            let subj = if let Some(s) = &t.subject {
                format!(
                    r#"<span class="archive-thread-subj">{}</span> — "#,
                    escape_html(s)
                )
            } else {
                String::new()
            };
            let thumb_html = if let Some(thumb) = &t.op_thumb {
                format!(
                    r#"<img src="/static/{}" class="archive-thumb" alt="thumb" loading="lazy">"#,
                    escape_html(thumb)
                )
            } else {
                String::new()
            };
            let ts = fmt_ts(t.created_at);
            body.push_str(&format!(
                r#"<div class="archive-row">
  {thumb}
  <div class="archive-row-info">
    <a href="/{board}/thread/{tid}" class="archive-thread-link">
      {subj}<span class="archive-preview">{preview}</span>
    </a>
    <span class="archive-meta">No.{tid} &mdash; {replies} replies &mdash; {ts} &#128190;</span>
  </div>
</div>"#,
                thumb = thumb_html,
                board = bs,
                tid = t.id,
                subj = subj,
                preview = escape_html(&preview),
                replies = t.reply_count,
                ts = ts,
            ));
        }
        body.push_str("</div>");
        body.push_str(&render_pagination(
            pagination,
            &format!("/{}/archive", board.short_name),
        ));
    }

    base_layout(
        &format!("/{}/  archive", board.short_name),
        Some(&board.short_name),
        &body,
        csrf_token,
        boards,
        collapse_greentext,
        true, // archive page — link is always shown
    )
}

pub fn admin_login_page(error: Option<&str>, csrf_token: &str, boards: &[Board]) -> String {
    let err_html = error
        .map(|e| format!(r#"<div class="error">{}</div>"#, escape_html(e)))
        .unwrap_or_default();

    let body = format!(
        r#"<div class="page-box admin-login">
<h2>[ admin login ]</h2>
{err}
<form method="POST" action="/admin/login">
<input type="hidden" name="_csrf" value="{csrf}">
<table>
<tr><td>username</td><td><input type="text" name="username" autofocus required autocomplete="username"></td></tr>
<tr><td>password</td><td><input type="password" name="password" required autocomplete="current-password"></td></tr>
<tr><td></td><td><button type="submit">authenticate</button></td></tr>
</table>
</form>
</div>"#,
        err = err_html,
        csrf = escape_html(csrf_token),
    );
    base_layout("admin login", None, &body, csrf_token, boards, false, false)
}

pub fn admin_panel_page(
    boards: &[Board],
    bans: &[Ban],
    filters: &[WordFilter],
    collapse_greentext: bool,
    csrf_token: &str,
    full_backups: &[BackupInfo],
    board_backups: &[BackupInfo],
    db_size_bytes: i64,
    reports: &[crate::models::ReportWithContext],
    appeals: &[crate::models::BanAppeal],
    site_name: &str,
    site_subtitle: &str,
    tor_address: Option<&str>,
) -> String {
    let mut board_cards = String::new();
    for b in boards {
        let checked = |v: bool| if v { " checked" } else { "" };
        board_cards.push_str(&format!(
            r#"<details class="board-settings-card">
<summary>/{short}/ — {name} {nsfw_tag}</summary>
<form method="POST" action="/admin/board/settings" class="board-settings-form">
<input type="hidden" name="_csrf"     value="{csrf}">
<input type="hidden" name="board_id"  value="{id}">
<div class="board-settings-grid">
  <label>Name<input type="text" name="name" value="{name_raw}" maxlength="64" required></label>
  <label>Description<input type="text" name="description" value="{desc_raw}" maxlength="256"></label>
  <label>Bump limit<input type="number" name="bump_limit" value="{bump}" min="1" max="10000"></label>
  <label>Max threads<input type="number" name="max_threads" value="{maxt}" min="1" max="1000"></label>
</div>
<div class="board-settings-checks">
  <label><input type="checkbox" name="nsfw"            value="1"{nsfw_ck}> NSFW</label>
  <label><input type="checkbox" name="allow_images"    value="1"{img_ck}>  Allow images</label>
  <label><input type="checkbox" name="allow_video"     value="1"{vid_ck}>  Allow video</label>
  <label><input type="checkbox" name="allow_audio"     value="1"{aud_ck}>  Allow audio</label>
  <label><input type="checkbox" name="allow_tripcodes" value="1"{trip_ck}> Allow tripcodes</label>
  <label><input type="checkbox" name="allow_archive"   value="1"{archive_ck}> Enable archive</label>
  <label><input type="checkbox" name="allow_video_embeds" value="1"{embeds_ck}> Embed video links (YouTube / Invidious / Streamable)</label>
  <label><input type="checkbox" name="allow_captcha"      value="1"{captcha_ck}> PoW CAPTCHA on new threads (hashcash, JS-solved)</label>
  <label><input type="checkbox" name="allow_editing"   value="1"{edit_ck}>
    Allow post editing</label>
</div>
<div class="board-settings-grid edit-window-row" style="margin-top:0.4rem;{edit_win_display}">
  <label title="How long (seconds) after posting a user may edit. 0 = use default (300 s).">
    Edit window (s)<input type="number" name="edit_window_secs" value="{edit_win}" min="0" max="86400">
  </label>
</div>
<div class="board-settings-actions">
  <button type="submit">save settings</button>
</div>
</form>
<!-- FIX[LOW-10]: Delete form is now OUTSIDE the settings form.
     Nested <form> elements are invalid HTML per spec; browsers discard
     the inner form's association unpredictably. -->
<form method="POST" action="/admin/board/delete" style="display:inline;margin-top:4px">
  <input type="hidden" name="_csrf"     value="{csrf}">
  <input type="hidden" name="board_id"  value="{id}">
  <button type="submit" class="btn-danger"
          data-confirm="Delete /{short}/ and ALL its content?">delete board</button>
</form>
<a href="/admin/board/backup/{short}" style="display:inline-block;margin-left:0.5rem;margin-top:4px">
  <button type="button">&#8659; download to computer /{short}/</button>
</a>
<form method="POST" action="/admin/board/backup/create" style="display:inline-block;margin-left:0.25rem;margin-top:4px">
  <input type="hidden" name="_csrf" value="{csrf}">
  <input type="hidden" name="board_short" value="{short}">
  <button type="submit">&#128190; save to server /{short}/</button>
</form>
</details>"#,
            short = escape_html(&b.short_name),
            name = escape_html(&b.name),
            nsfw_tag = if b.nsfw { r#"<span class="tag nsfw-tag">NSFW</span>"# } else { "" },
            csrf = escape_html(csrf_token),
            id = b.id,
            name_raw = escape_html(&b.name),
            desc_raw = escape_html(&b.description),
            bump = b.bump_limit,
            maxt = b.max_threads,
            edit_win = b.edit_window_secs,
            edit_win_display = if b.allow_editing { "" } else { "display:none" },
            nsfw_ck = checked(b.nsfw),
            img_ck = checked(b.allow_images),
            vid_ck = checked(b.allow_video),
            aud_ck = checked(b.allow_audio),
            trip_ck = checked(b.allow_tripcodes),
            archive_ck = checked(b.allow_archive),
            edit_ck = checked(b.allow_editing),
            embeds_ck = checked(b.allow_video_embeds),
            captcha_ck = checked(b.allow_captcha),
        ));
    }

    let mut ban_rows = String::new();
    for ban in bans {
        let expires = ban
            .expires_at
            .map(fmt_ts)
            .unwrap_or_else(|| "permanent".to_string());
        ban_rows.push_str(&format!(
            r#"<tr>
<td class="ip-hash">{}</td><td>{}</td><td>{}</td>
<td>
<form method="POST" action="/admin/ban/remove" style="display:inline">
<input type="hidden" name="_csrf" value="{csrf}">
<input type="hidden" name="ban_id" value="{id}">
<button type="submit">lift</button>
</form>
</td>
</tr>"#,
            // FIX[MEDIUM-13]: Use .get(..16) instead of [..16] to avoid a panic
            // if ip_hash is somehow shorter than 16 chars (e.g. from a migrated DB).
            escape_html(ban.ip_hash.get(..16).unwrap_or(&ban.ip_hash)),
            escape_html(ban.reason.as_deref().unwrap_or("")),
            escape_html(&expires),
            csrf = escape_html(csrf_token),
            id = ban.id,
        ));
    }

    let mut filter_rows = String::new();
    for f in filters {
        filter_rows.push_str(&format!(
            r#"<tr>
<td>{}</td><td>{}</td>
<td>
<form method="POST" action="/admin/filter/remove" style="display:inline">
<input type="hidden" name="_csrf" value="{csrf}">
<input type="hidden" name="filter_id" value="{id}">
<button type="submit">remove</button>
</form>
</td>
</tr>"#,
            escape_html(&f.pattern),
            escape_html(&f.replacement),
            csrf = escape_html(csrf_token),
            id = f.id,
        ));
    }

    // ── Full backup file list ─────────────────────────────────────────────────
    let mut full_backup_rows = String::new();
    if full_backups.is_empty() {
        full_backup_rows.push_str(
            "<tr><td colspan=\"4\" style=\"color:var(--text-dim);text-align:center\">no backups yet</td></tr>",
        );
    }
    for bf in full_backups {
        let size_fmt = format_file_size(bf.size_bytes as i64);
        full_backup_rows.push_str(&format!(
            r#"<tr>
<td style="word-break:break-all">{fname}</td>
<td style="white-space:nowrap">{size}</td>
<td style="white-space:nowrap">{modified}</td>
<td style="white-space:nowrap">
  <a href="/admin/backup/download/full/{fname}" style="margin-right:0.4rem">&#8659; download to computer</a>
  <form method="POST" action="/admin/backup/restore-saved" style="display:inline;margin-right:0.4rem">
    <input type="hidden" name="_csrf" value="{csrf}">
    <input type="hidden" name="filename" value="{fname}">
    <button type="submit" data-confirm="WARNING: Restore from {fname}? This will overwrite the live database and all uploads. Cannot be undone.">&#8635; restore</button>
  </form>
  <form method="POST" action="/admin/backup/delete" style="display:inline">
    <input type="hidden" name="_csrf" value="{csrf}">
    <input type="hidden" name="kind" value="full">
    <input type="hidden" name="filename" value="{fname}">
    <button type="submit" class="btn-danger" data-confirm="Delete {fname}? This cannot be undone.">&#10005; delete</button>
  </form>
</td>
</tr>"#,
            fname = escape_html(&bf.filename),
            size = size_fmt,
            modified = escape_html(&bf.modified),
            csrf = escape_html(csrf_token),
        ));
    }

    // ── Board backup file list ────────────────────────────────────────────────
    let mut board_backup_rows = String::new();
    if board_backups.is_empty() {
        board_backup_rows.push_str(
            "<tr><td colspan=\"4\" style=\"color:var(--text-dim);text-align:center\">no board backups yet</td></tr>",
        );
    }
    for bf in board_backups {
        let size_fmt = format_file_size(bf.size_bytes as i64);
        board_backup_rows.push_str(&format!(
            r#"<tr>
<td style="word-break:break-all">{fname}</td>
<td style="white-space:nowrap">{size}</td>
<td style="white-space:nowrap">{modified}</td>
<td style="white-space:nowrap">
  <a href="/admin/backup/download/board/{fname}" style="margin-right:0.4rem">&#8659; download to computer</a>
  <form method="POST" action="/admin/board/backup/restore-saved" style="display:inline;margin-right:0.4rem">
    <input type="hidden" name="_csrf" value="{csrf}">
    <input type="hidden" name="filename" value="{fname}">
    <button type="submit" data-confirm="WARNING: Restore board from {fname}? This will wipe and replace that board. Cannot be undone.">&#8635; restore</button>
  </form>
  <form method="POST" action="/admin/backup/delete" style="display:inline">
    <input type="hidden" name="_csrf" value="{csrf}">
    <input type="hidden" name="kind" value="board">
    <input type="hidden" name="filename" value="{fname}">
    <button type="submit" class="btn-danger" data-confirm="Delete {fname}? This cannot be undone.">&#10005; delete</button>
  </form>
</td>
</tr>"#,
            fname = escape_html(&bf.filename),
            size = size_fmt,
            modified = escape_html(&bf.modified),
            csrf = escape_html(csrf_token),
        ));
    }

    // ── Report inbox ──────────────────────────────────────────────────────────
    let report_count = reports.len();
    let report_badge = if report_count > 0 {
        format!(r#" <span class="report-badge">{}</span>"#, report_count)
    } else {
        String::new()
    };

    let mut report_rows = String::new();
    if reports.is_empty() {
        report_rows.push_str(
            r#"<tr><td colspan="5" style="color:var(--text-dim);text-align:center">no open reports</td></tr>"#,
        );
    }
    for rc in reports {
        let preview = escape_html(rc.post_preview.trim());
        let reason = escape_html(&rc.report.reason);
        let age = fmt_ts(rc.report.created_at);
        let ip_short = rc.post_ip_hash.get(..16).unwrap_or(&rc.post_ip_hash);
        report_rows.push_str(&format!(
            r#"<tr>
<td><a href="/{board}/thread/{tid}#p{pid}" title="view post">/{board}/ No.{pid}</a></td>
<td style="max-width:240px;overflow:hidden;text-overflow:ellipsis;white-space:nowrap" title="{preview}">{preview}</td>
<td>{reason}</td>
<td style="white-space:nowrap;font-size:0.78rem">{age}</td>
<td style="white-space:nowrap">
  <form method="POST" action="/admin/report/resolve" style="display:inline">
    <input type="hidden" name="_csrf"      value="{csrf}">
    <input type="hidden" name="report_id"  value="{rid}">
    <button type="submit">&#10003; resolve</button>
  </form>
  <form method="POST" action="/admin/report/resolve" style="display:inline;margin-left:0.35rem"
        data-confirm-submit="Resolve report AND permanently ban this IP?">
    <input type="hidden" name="_csrf"      value="{csrf}">
    <input type="hidden" name="report_id"  value="{rid}">
    <input type="hidden" name="ban_ip_hash" value="{ip_hash}">
    <input type="hidden" name="ban_reason"  value="Reported content">
    <button type="submit" class="btn-danger">&#10003; resolve + ban</button>
  </form>
</td>
</tr>"#,
            board   = escape_html(&rc.board_short),
            tid     = rc.report.thread_id,
            pid     = rc.report.post_id,
            preview = preview,
            reason  = reason,
            age     = escape_html(&age),
            csrf    = escape_html(csrf_token),
            rid     = rc.report.id,
            ip_hash = escape_html(&rc.post_ip_hash),
        ));
        let _ = ip_short; // suppress unused warning
    }

    // ── Ban appeals section ───────────────────────────────────────────────
    let appeal_badge = if !appeals.is_empty() {
        format!(r#" <span class="report-badge">{}</span>"#, appeals.len())
    } else {
        String::new()
    };

    let mut appeal_rows = String::new();
    if appeals.is_empty() {
        appeal_rows.push_str(
            r#"<tr><td colspan="4" style="color:var(--text-dim);text-align:center">no open appeals</td></tr>"#,
        );
    }
    for a in appeals {
        let reason = escape_html(a.reason.trim());
        let age = fmt_ts(a.created_at);
        let ip_short = a.ip_hash.get(..16).unwrap_or(&a.ip_hash);
        appeal_rows.push_str(&format!(
            r#"<tr>
<td style="font-size:0.78rem;font-family:monospace">{ip_short}…</td>
<td style="max-width:300px;overflow:hidden;text-overflow:ellipsis;white-space:nowrap" title="{reason}">{reason}</td>
<td style="white-space:nowrap;font-size:0.78rem">{age}</td>
<td style="white-space:nowrap">
  <form method="POST" action="/admin/appeal/dismiss" style="display:inline">
    <input type="hidden" name="_csrf"      value="{csrf}">
    <input type="hidden" name="appeal_id"  value="{aid}">
    <button type="submit">✕ dismiss</button>
  </form>
  <form method="POST" action="/admin/appeal/accept" style="display:inline;margin-left:0.35rem"
        data-confirm-submit="Accept appeal and lift ban for this IP?">
    <input type="hidden" name="_csrf"      value="{csrf}">
    <input type="hidden" name="appeal_id"  value="{aid}">
    <input type="hidden" name="ip_hash"    value="{ip_hash}">
    <button type="submit" class="btn-success">✓ accept + unban</button>
  </form>
</td>
</tr>"#,
            ip_short = ip_short,
            reason   = reason,
            age      = escape_html(&age),
            csrf     = escape_html(csrf_token),
            aid      = a.id,
            ip_hash  = escape_html(&a.ip_hash),
        ));
    }

    let body = format!(
        r#"<div class="admin-panel">
<h1>[ admin panel ]</h1>
<form method="POST" action="/admin/logout">
<input type="hidden" name="_csrf" value="{csrf}">
<button type="submit">logout</button>
</form>

<section class="admin-section" id="reports">
<h2>// report inbox{report_badge}</h2>
<table class="admin-table">
<thead><tr><th>post</th><th>content preview</th><th>reason</th><th>filed</th><th>action</th></tr></thead>
<tbody>{report_rows}</tbody>
</table>
</section>

<section class="admin-section" id="appeals">
<h2>// ban appeals{appeal_badge}</h2>
<table class="admin-table">
<thead><tr><th>ip (partial)</th><th>appeal message</th><th>filed</th><th>action</th></tr></thead>
<tbody>{appeal_rows}</tbody>
</table>
</section>

<section class="admin-section">
<h2>// boards</h2>
<div class="admin-board-cards">{board_cards}</div>
<h3>create board</h3>
<form method="POST" action="/admin/board/create">
<input type="hidden" name="_csrf" value="{csrf}">
<input type="text" name="short_name" placeholder="short (e.g. tech)" maxlength="8" required>
<input type="text" name="name" placeholder="full name" maxlength="64" required>
<input type="text" name="description" placeholder="description" maxlength="256">
<label style="color:var(--text-dim);font-size:0.8rem"><input type="checkbox" name="nsfw" value="1"> NSFW</label>
<button type="submit">create</button>
</form>
</section>

<section class="admin-section">
<h2>// active bans</h2>
<table class="admin-table">
<thead><tr><th>ip hash (partial)</th><th>reason</th><th>expires</th><th>action</th></tr></thead>
<tbody>{ban_rows}</tbody>
</table>
<h3>add ban</h3>
<form method="POST" action="/admin/ban/add">
<input type="hidden" name="_csrf" value="{csrf}">
<input type="text" name="ip_hash" placeholder="ip hash" required>
<input type="text" name="reason" placeholder="reason">
<input type="text" name="duration_hours" placeholder="hours (blank=perm)" style="width:120px">
<button type="submit">ban</button>
</form>
</section>

<section class="admin-section">
<h2>// word filters</h2>
<table class="admin-table">
<thead><tr><th>pattern</th><th>replacement</th><th>action</th></tr></thead>
<tbody>{filter_rows}</tbody>
</table>
<h3>add filter</h3>
<form method="POST" action="/admin/filter/add">
<input type="hidden" name="_csrf" value="{csrf}">
<input type="text" name="pattern" placeholder="pattern to match" required>
<input type="text" name="replacement" placeholder="replace with">
<button type="submit">add</button>
</form>
</section>

<section class="admin-section">
<h2>// site settings</h2>
<form method="POST" action="/admin/site/settings">
<input type="hidden" name="_csrf" value="{csrf}">
<div class="board-settings-grid" style="margin-bottom:0.75rem">
  <label>Site name
    <input type="text" name="site_name" value="{site_name_val}" maxlength="64" placeholder="RustChan"
           style="font-family:inherit">
  </label>
  <label>Home page subtitle
    <input type="text" name="site_subtitle" value="{site_subtitle_val}" maxlength="128" placeholder="select board to proceed"
           style="font-family:inherit">
  </label>
</div>
<div class="board-settings-checks" style="margin-bottom:0.75rem">
  <label title="When enabled, 3 or more consecutive greentext lines are wrapped in a collapsible block. Existing posts are not affected — only new posts use the current setting.">
    <input type="checkbox" name="collapse_greentext" value="1"{collapse_ck}>
    Collapse long greentext walls (3+ lines) into expandable blocks
  </label>
</div>
<button type="submit">save settings</button>
</form>
</section>

<section class="admin-section">
<h2>// moderation log <a href="/admin/mod-log" style="font-size:0.78rem;margin-left:0.6rem;color:var(--text-dim)">[ view full log ]</a></h2>
<p style="color:var(--text-dim);font-size:0.82rem">All admin actions are recorded in the moderation log. Click <em>view full log</em> to browse the history.</p>
</section>

<section class="admin-section">
<h2>// backup &amp; restore</h2>
<p style="color:var(--text-dim);font-size:0.85rem">Full backups include the complete database and all uploaded files. <strong>Save to server</strong> stores the backup in <code>rustchan-data/full-backups/</code> on the server filesystem (listed below). <strong>Restore from local file</strong> uploads a zip from your computer.</p>
<div style="display:flex;gap:1rem;flex-wrap:wrap;align-items:center;margin-top:0.75rem;margin-bottom:0.75rem">
<form method="POST" action="/admin/backup/create">
<input type="hidden" name="_csrf" value="{csrf}">
<button type="submit">&#128190; save to server</button>
</form>
<form method="POST" action="/admin/restore" enctype="multipart/form-data" style="display:flex;gap:0.5rem;align-items:center;flex-wrap:wrap">
<input type="hidden" name="_csrf" value="{csrf}">
<input type="file" name="backup_file" accept=".zip" required style="color:var(--text)">
<button type="submit" class="btn-danger"
        data-confirm="WARNING: This will overwrite the database and all uploaded files. Cannot be undone. Continue?">&#8635; restore from local file</button>
</form>
</div>
<table style="width:100%;border-collapse:collapse;font-size:0.85rem">
<thead><tr style="color:var(--text-dim)"><th style="text-align:left">filename</th><th style="text-align:left">size</th><th style="text-align:left">created</th><th></th></tr></thead>
<tbody>{full_backup_rows}</tbody>
</table>
</section>

<section class="admin-section">
<h2>// board backup &amp; restore</h2>
<p style="color:var(--text-dim);font-size:0.85rem">Board backups cover a single board. Use <em>save to server</em> on a board card above to store the backup in <code>rustchan-data/board-backups/</code>, or use the table below to download, restore, or delete saved backups. <strong>Restore from local file</strong> uploads a zip from your computer.</p>
<div style="margin-top:0.5rem;margin-bottom:0.75rem">
<form method="POST" action="/admin/board/restore" enctype="multipart/form-data" style="display:flex;gap:0.5rem;align-items:center;flex-wrap:wrap">
<input type="hidden" name="_csrf" value="{csrf}">
<input type="file" name="backup_file" accept=".zip" required style="color:var(--text)">
<button type="submit" class="btn-danger"
        data-confirm="WARNING: This will wipe and replace the board from the backup zip. Other boards are unaffected. Continue?">&#8635; restore board from local file</button>
</form>
</div>
<table style="width:100%;border-collapse:collapse;font-size:0.85rem">
<thead><tr style="color:var(--text-dim)"><th style="text-align:left">filename</th><th style="text-align:left">size</th><th style="text-align:left">created</th><th></th></tr></thead>
<tbody>{board_backup_rows}</tbody>
</table>
</section>

<section class="admin-section">
<h2>// database maintenance</h2>
<p style="color:var(--text-dim);font-size:0.85rem">
  Current database size: <strong>{db_size_str}</strong>.
  Running <strong>VACUUM</strong> rewrites the database file compactly, reclaiming space left after
  bulk deletions (deleted threads, pruned posts, etc.).  This may take a few seconds on large
  databases and briefly blocks writes.
</p>
<form method="POST" action="/admin/vacuum">
  <input type="hidden" name="_csrf" value="{csrf}">
  <button type="submit"
          data-confirm="Run VACUUM? This will briefly block the database while it rebuilds. Continue?">&#x1F9F9; run VACUUM</button>
</form>
</section>
{tor_section}
</div>"#,
        csrf = escape_html(csrf_token),
        board_cards = board_cards,
        ban_rows = ban_rows,
        filter_rows = filter_rows,
        collapse_ck = if collapse_greentext { " checked" } else { "" },
        full_backup_rows = full_backup_rows,
        board_backup_rows = board_backup_rows,
        db_size_str = format_file_size(db_size_bytes),
        report_rows = report_rows,
        report_badge = report_badge,
        appeal_rows = appeal_rows,
        appeal_badge = appeal_badge,
        site_name_val = escape_html(site_name),
        site_subtitle_val = escape_html(site_subtitle),
        tor_section = match tor_address {
            Some(addr) => format!(
                r#"<section class="admin-section" style="border-top:1px solid var(--border);padding-top:1rem;margin-top:0;text-align:center">
<p style="color:var(--text-dim);font-size:0.82rem;margin:0">
  <code style="user-select:all;color:var(--text)">{}</code>
</p>
</section>"#,
                escape_html(addr)
            ),
            None => String::new(),
        },
    );

    base_layout("admin panel", None, &body, csrf_token, boards, false, false)
}

// ─── Edit post page ───────────────────────────────────────────────────────────

pub fn edit_post_page(
    board: &Board,
    post: &Post,
    csrf_token: &str,
    boards: &[Board],
    prefill_token: &str,
    error: Option<&str>,
    collapse_greentext: bool,
) -> String {
    let error_html = error
        .map(|msg| {
            format!(
                r#"<div class="post-error-banner">&#9888; {}</div>"#,
                escape_html(msg)
            )
        })
        .unwrap_or_default();

    let body = format!(
        r#"{error_html}
<div class="board-header">
  <a href="/{board}/thread/{tid}#p{pid}">[ return to thread ]</a>
</div>
<div class="page-box">
<div class="post-form-container">
<div class="post-form-title">[ edit post No.{pid} ]</div>
<p style="font-size:0.8rem;color:var(--text-dim)">
  You can edit this post within the board's edit window.<br>
  Your edit token is required to confirm the edit.
</p>
<form class="post-form" method="POST" action="/{board}/post/{pid}/edit">
  <input type="hidden" name="_csrf" value="{csrf}">
  <table>
    <tr><td>body</td>
        <td><textarea name="body" rows="6" maxlength="4096">{current_body}</textarea></td></tr>
    <tr><td>edit token</td>
        <td><input type="text" name="deletion_token" value="{token}" placeholder="your edit token" maxlength="64"></td></tr>
    <tr><td></td>
        <td><button type="submit">save edit</button>
            <a href="/{board}/thread/{tid}#p{pid}" style="margin-left:1rem">cancel</a></td></tr>
  </table>
</form>
</div>
</div>"#,
        error_html = error_html,
        board = escape_html(&board.short_name),
        tid = post.thread_id,
        pid = post.id,
        csrf = escape_html(csrf_token),
        current_body = escape_html(&post.body),
        token = escape_html(prefill_token),
    );

    base_layout(
        &format!("edit post No.{} — /{}/", post.id, board.short_name),
        Some(&board.short_name),
        &body,
        csrf_token,
        boards,
        collapse_greentext,
        board.allow_archive,
    )
}

